   1 &amp; { - 2} &amp; 3  \cr 

 } } \right] = \left[ {\matrix{
   1 &amp; 0 &amp; 0  \cr 
   0 &amp; 1 &amp; 0  \cr 
   0 &amp; 0 &amp; 1  \cr 

 } } \right]$$ 
<br><br>$$ \Rightarrow {1 \over {10}}\left[ {\matrix{
